public interface ProductFullProjection {
    UUID getId();
    String getName();
    ProductType getProductType();
    // ... solo los campos necesarios para este contexto
}

public class ProductEntityMapper {
    // Sobrecarga para manejar proyecciones optimizadas
    public static Product toDomain(ProductFullProjection projection) {
        return Product.builder()
                .id(projection.getId().toString())
                .name(projection.getName())
                // ... solo los campos necesarios para este contexto
                .build();
    }
}

// ViewModel: Cerebro de la vista, encapsula lógica y estado
export default function ViewModel() {
    const { productRepository } = useRepositories();
    const [products, setProducts] = useState<Product[]>([]);

    const fetchProducts = async () => {
        const response = await productRepository.getAll(...);
        setProducts(Product.fromList(response.products));
    };

    return {
        products,
        onSearch: fetchProducts,
        // ... expone solo lo necesario para la UI
    };
}

// UI (Route): Sin lógica, solo representación
export default function ProductsListRoute() {
    const { products, onSearch, (...) } = ViewModel();

    return (
        <Layout>
            <BigTitle text="Lista de productos" />
            <ProductFilter onSearch={onSearch} (...) />
            <Table data={products} (...) />
        </Layout>
    );
}

@Component
@AllArgsConstructor
public class PreseaSyncScheduler {
    private final FtpHelper ftpHelper;
    private final ProcessPreseaDispatchNotesUseCase processUseCase;

    @Scheduled(cron = "0 0 1 * * ?", zone = "America/Argentina/Buenos_Aires")
    public void syncDispatchNotes() {
        try {
            // 1. Ingesta automática mediante FTP
            this.ftpHelper.downloadFile(REMOTE_FILE, LOCAL_DIR, FILENAME);

            // 2. Procesamiento de datos y actualización de stock
            this.processUseCase.execute(new ProcessPreseaDispatchNotesUseCase.Command(PATH));
        }
        catch (Exception e) {
            log.error("Error en sincronización automática: {}", e.getMessage());
        }
    }
}
